+    #[test]
+    fn to_timedelta_hms_string() {
+        let s = Series::from_values(
+            "td",
+            vec![0_i64.into()],
+            vec![Scalar::Utf8("02:30:45".into())],
+        )
+        .unwrap();
+        let result = super::to_timedelta(&s).unwrap();
